PowerShell<pre><code>function Invoke-Batch {
    param(
        [array]$Items,
        [int]$BatchSize = 25,
        [scriptblock]$ProcessBatch
    )
    for ($i = 0; $i -lt $Items.Count; $i += $BatchSize) {
        $batch = $Items[$i..([Math]::Min($i + $BatchSize - 1, $Items.Count - 1))]
        &amp; $ProcessBatch -Batch $batch
        Write-Host "Processed $($i + $batch.Count) / $($Items.Count)"
    }
}
</code></pre>

PowerShell<pre><code>class RequestBuilder {
    [string]$Method
    [string]$Uri
    [hashtable]$Headers
    [hashtable]$Query
    [object]$Body

    RequestBuilder() {
        $this.Headers = @{}
        $this.Query = @{}
    }

    [RequestBuilder] WithMethod([string]$method) {
        $this.Method = $method
        return $this
    }

    [RequestBuilder] WithUri([string]$uri) {
        $this.Uri = $uri
        return $this
    }

    [RequestBuilder] WithHeader([string]$key, [string]$value) {
        $this.Headers[$key] = $value
        return $this
    }

    [RequestBuilder] WithQuery([string]$key, [string]$value) {
        $this.Query[$key] = $value
        return $this
    }

    [hashtable] Build() {
        $uriBuilder = [System.UriBuilder]::new($this.Uri)
        if ($this.Query.Count -gt 0) {
            $uriBuilder.Query = ($this.Query.GetEnumerator() |
                ForEach-Object { "$($_.Key)=$([System.Web.HttpUtility]::UrlEncode($_.Value))" }) -join "&amp;"
        }
        return @{
            Method  = $this.Method
            Uri     = $uriBuilder.Uri.ToString()
            Headers = $this.Headers
        }
    }
}

# Fluent usage
$request = [RequestBuilder]::new()
    .WithMethod("GET")
    .WithUri("https://api.example.com/v1/items")
    .WithHeader("Authorization", "Bearer $token")
    .WithHeader("Accept", "application/json")
    .WithQuery("limit", "100")
    .WithQuery("offset", "0")
    .Build()
</code></pre>

PowerShell<pre><code>function Protect-AesGcm {
    param([string]$PlainText, [byte[]]$Key)
    $aes = [System.Security.Cryptography.AesGcm]::new($Key)
    $nonce = New-Object byte[] 12
    [Security.Cryptography.RandomNumberGenerator]::Fill($nonce)
    $plaintextBytes = [System.Text.Encoding]::UTF8.GetBytes($PlainText)
    $ciphertext = New-Object byte[] $plaintextBytes.Length
    $tag = New-Object byte[] 16
    $aes.Encrypt($nonce, $plaintextBytes, $ciphertext, $tag)
    return @{ Nonce = $nonce; Ciphertext = $ciphertext; Tag = $tag }
}

function Unprotect-AesGcm {
    param([byte[]]$Key, [byte[]]$Nonce, [byte[]]$Ciphertext, [byte[]]$Tag)
    $aes = [System.Security.Cryptography.AesGcm]::new($Key)
    $plaintext = New-Object byte[] $Ciphertext.Length
    $aes.Decrypt($Nonce, $Ciphertext, $Tag, $plaintext)
    return [System.Text.Encoding]::UTF8.GetString($plaintext)
}
</code></pre>

